SELECT LOWER(S.GENERO) AS GENERO, COUNT(SP.PK) AS TOTAL FROM SERVIDOR_PROJ SP JOIN PROJ P ON SP.FK_PROJ = P.PK JOIN SERVIDOR S ON SP.FK_SIAPE = S.PK_SIAPE WHERE LOWER(COALESCE(P.AREA_CONHECIMENTO,'')) LIKE '%engenharia civil%' AND LOWER(COALESCE(S.SIGLA_CAMPUS,'')) = 'luz' AND SP.DATA_ENTRADA >= (DATE('now', '-5 years')) GROUP BY LOWER(S.GENERO) ORDER BY TOTAL DESC LIMIT 1